import{_ as e,o as i,c as t,a as l}from"./app-31c067ee.js";const c={},r=l('<h3 id="git-commit-规范的类别-常见类别如下" tabindex="-1"><a class="header-anchor" href="#git-commit-规范的类别-常见类别如下" aria-hidden="true">#</a> git commit 规范的类别，常见类别如下：</h3><ul><li>feat：新增功能（feature）</li><li>fix：修复补丁（bug）</li><li>docs：修订文档，如 Readme, Change Log, Contribute 等</li><li>refactor：代码重构，未新增任何功能和修复任何 bug</li><li>style： 仅调整空格、格式缩进等（不改变代码逻辑的变动）</li><li>perf：优化相关，改善性能和体验的修改</li><li>test：测试用例的增加/修改</li><li>chore：非 src 和 test 的修改</li><li>merge：合并分支或冲突等</li><li>revert： 回滚到上一个版本</li><li>build：改变构建流程，新增依赖库、工具等（例如 webpack、maven 修改）</li><li>ci：自动化流程配置修改</li></ul>',2),a=[r];function o(s,n){return i(),t("div",null,a)}const _=e(c,[["render",o],["__file","gitcomrule.html.vue"]]);export{_ as default};
